**Word Counter Program in C++**
================================

This program reads a text file line by line and counts the number of occurrences of a specific word in the file.

### Code

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <vector>

// Function to count the occurrences of a word in a line
int countWordOccurrences(const std::string& line, const std::string& word) {
    int count = 0;
    size_t pos = line.find(word);
    while (pos!= std::string::npos) {
        count++;
        pos = line.find(word, pos + 1);
    }
    return count;
}

// Function to count the occurrences of a word in a file
int countWordOccurrencesInFile(const std::string& filename, const std::string& word) {
    int totalCount = 0;
    std::ifstream file(filename);
    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            totalCount += countWordOccurrences(line, word);
        }
        file.close();
    } else {
        std::cerr << "Unable to open file " << filename << std::endl;
    }
    return totalCount;
}

int main() {
